import React, { useRef, useEffect, useState } from 'react';
import { BlockMath } from 'react-katex';

function VisualExplainCard({ imageBase64, steps, audioChunks }) {
  const canvasRef = useRef(null);
  const [currentStep, setCurrentStep] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const audioRef = useRef(null);
  const intervalRef = useRef(null);

  const safeSteps = Array.isArray(steps) ? steps : [];
  const hasAudio = audioChunks && audioChunks.trim().length > 0;

  useEffect(() => {
    if (hasAudio) {
      audioRef.current = new Audio(`data:audio/mp3;base64,${audioChunks}`);
    }
    return () => {
      if (audioRef.current) {
        audioRef.current.pause();
        audioRef.current = null;
      }
      if (intervalRef.current) clearInterval(intervalRef.current);
    };
  }, [audioChunks, hasAudio]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas || !imageBase64) return;
    const ctx = canvas.getContext('2d');
    const img = new Image();
    img.src = `data:image/png;base64,${imageBase64}`;
    img.onload = () => {
      canvas.width = img.width;
      canvas.height = img.height;
      ctx.drawImage(img, 0, 0);
    };
  }, [imageBase64]);

  const startPlayback = () => {
    if (!audioRef.current) {
      alert('语音数据尚未加载，请稍后重试或重新生成讲解');
      return;
    }
    audioRef.current.currentTime = 0;
    audioRef.current.play().catch(() => { });
    setIsPlaying(true);

    let stepIndex = 0;
    setCurrentStep(stepIndex);
    const duration = (audioRef.current.duration || 20) * 1000;
    const stepDuration = duration / safeSteps.length;

    intervalRef.current = setInterval(() => {
      stepIndex++;
      if (stepIndex >= safeSteps.length) {
        clearInterval(intervalRef.current);
        setIsPlaying(false);
        return;
      }
      setCurrentStep(stepIndex);
    }, stepDuration);
  };

  const stopPlayback = () => {
    if (audioRef.current) audioRef.current.pause();
    if (intervalRef.current) clearInterval(intervalRef.current);
    setIsPlaying(false);
  };

  const renderText = (text) => {
    if (!text) return null;
    const parts = text.split(/(\$\$.*?\$\$|\$.*?\$)/gs);
    return parts.map((part, idx) => {
      if (part.startsWith('$$') && part.endsWith('$$'))
        return <BlockMath key={idx} math={part.slice(2, -2)} />;
      if (part.startsWith('$') && part.endsWith('$'))
        return <BlockMath key={idx} math={part.slice(1, -1)} />;
      return <span key={idx}>{part}</span>;
    });
  };

  if (safeSteps.length === 0) {
    return (
      <div className="bg-white rounded-2xl p-4 shadow-md my-2">
        <p className="text-gray-500 text-sm">讲解内容正在准备中...</p>
      </div>
    );
  }

  return (
    <div className="bg-white rounded-2xl p-4 shadow-md my-2 max-w-full">
      <div className="flex justify-between items-center mb-3">
        <h3 className="font-semibold text-gray-800">👩‍🏫 AI 超拟人老师</h3>
        <button
          onClick={isPlaying ? stopPlayback : startPlayback}
          className={`px-4 py-1.5 rounded-full text-xs font-semibold ${isPlaying ? 'bg-red-100 text-red-700 hover:bg-red-200' : 'bg-blue-100 text-blue-700 hover:bg-blue-200'
            }`}
        >
          {isPlaying ? '⏹ 停止' : '▶ 播放讲解'}
        </button>
      </div>

      {imageBase64 && (
        <div className="relative bg-gray-100 rounded-lg overflow-hidden mb-3">
          <canvas ref={canvasRef} className="w-full" style={{ maxHeight: '40vh' }} />
        </div>
      )}

      <div className="w-full bg-gray-200 rounded-full h-1.5 mb-3">
        <div
          className="bg-blue-500 h-1.5 rounded-full transition-all duration-500"
          style={{ width: `${((currentStep + 1) / safeSteps.length) * 100}%` }}
        />
      </div>

      {safeSteps[currentStep] && (
        <div className="p-4 bg-blue-50 rounded-xl border border-blue-200 mb-3">
          <div className="text-sm text-gray-800 font-medium leading-relaxed">
            <span className="text-blue-600 mr-2 font-bold">
              步骤 {currentStep + 1}/{safeSteps.length}
            </span>
            {renderText(safeSteps[currentStep].text)}
          </div>
        </div>
      )}

      <div className="flex justify-center gap-2">
        {safeSteps.map((_, idx) => (
          <button
            key={idx}
            onClick={() => {
              if (isPlaying) stopPlayback();
              setCurrentStep(idx);
            }}
            className={`h-2 rounded-full transition-all duration-300 ${idx === currentStep ? 'w-6 bg-blue-500' : 'w-2 bg-gray-300'
              }`}
          />
        ))}
      </div>
    </div>
  );
}

export default VisualExplainCard;
